parameters.jsCode:
// Obtenemos el estado actual del ticket que encontramos
let estadoActual = $node["Limit2"].json["estado"];

// Definimos la lógica de progresión
let estados = {
  'Pendiente': 'En revisión',
  'En revisión': 'Aprobada',
  'Aprobada': 'Completada',
  'Completada': 'Pendiente' // Reinicia el ciclo
};

// Si por alguna razón no hay estado (hoja vacía), empezamos en Pendiente
let resultado = estados[estadoActual] || 'Pendiente';

return {
  nuevo_estado: resultado
};

parameters.text:
=✅ Ticket encontrado:

🎫 ID: {{ $json.id_ticket }}
🚦 Estado: {{ $json.estado }}
🛠️ Tipo: {{ $json.tipo }}
📝 Descripción: {{ $json.descripcion }}

parameters.jsCode:
const items = $input.all();

if (items.length === 0 || !items[0].json.id_ticket) {
  return [{
    json: {
      mensaje: "📭 No tienes solicitudes registradas aún.\n\nEscribe *1* para crear tu primera solicitud."
    }
  }];
}

let texto = `📋 *Tus solicitudes (${items.length}):*\n\n`;

for (const item of items) {
  const t = item.json;
  const estado = t.estado || 'Sin estado';
  const tipo = t.tipo || 'Sin tipo';
  const fecha = t.fecha_creacion ? t.fecha_creacion.substring(0, 10) : 'Sin fecha';

  texto += `🎫 *${t.id_ticket}*\n`;
  texto += `   📌 ${tipo} | 🚦 ${estado}\n`;
  texto += `   📝 ${t.descripcion}\n`;
  texto += `   📅 ${fecha}\n\n`;
}

texto += `Escribe *2* para consultar el detalle de un ticket específico.`;

return [{ json: { mensaje: texto } }];
